-- RealityDB Healthcare Template | Seed: 42 | ~170 rows
-- Lifecycle: cancelled/no_show appointments → completed_at = NULL
-- Temporal: completed_at > created_at
-- Weights: appt_status completed=60% scheduled=15% cancelled=15% no_show=10% | gender female=52% male=47% non_binary=1%

CREATE TABLE patients (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, email TEXT, date_of_birth DATE NOT NULL, gender TEXT NOT NULL, blood_type TEXT, insurance_provider TEXT, created_at TIMESTAMP NOT NULL);
CREATE TABLE appointments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), patient_id UUID NOT NULL REFERENCES patients(id), provider TEXT NOT NULL, type TEXT NOT NULL, status TEXT NOT NULL, scheduled_at TIMESTAMP NOT NULL, completed_at TIMESTAMP, created_at TIMESTAMP NOT NULL);
CREATE TABLE encounters (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), appointment_id UUID NOT NULL REFERENCES appointments(id), type TEXT NOT NULL, diagnosis_code TEXT, notes TEXT, duration_minutes INTEGER, created_at TIMESTAMP NOT NULL);
CREATE TABLE billing (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), encounter_id UUID NOT NULL REFERENCES encounters(id), amount NUMERIC(10,2) NOT NULL, status TEXT NOT NULL, insurance_covered NUMERIC(10,2), patient_responsibility NUMERIC(10,2), paid_at TIMESTAMP, created_at TIMESTAMP NOT NULL);




